import type { ComponentProps, ComponentRef, CSSProperties } from 'react';
import { Splitter as SplitterPrimitive } from '@ark-ui/react/splitter';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Splitter.module.css';

const rootStyle = {
  width: 'var(--splitter-width, 100%)',
  height: 'var(--splitter-height, 28rem)',
} satisfies CSSProperties;

const SplitterRoot = forwardRef<
  ComponentRef<typeof SplitterPrimitive.Root>,
  ComponentProps<typeof SplitterPrimitive.Root>
>(function SplitterRoot({ className, style, ...props }, ref) {
  return (
    <SplitterPrimitive.Root
      ref={ref}
      data-slot="splitter-root"
      className={clsx(styles.root, normalizeClassName(className))}
      style={{ ...rootStyle, ...style }}
      {...props}
    />
  );
});

const SplitterRootProvider = forwardRef<
  ComponentRef<typeof SplitterPrimitive.RootProvider>,
  ComponentProps<typeof SplitterPrimitive.RootProvider>
>(function SplitterRootProvider({ className, style, ...props }, ref) {
  return (
    <SplitterPrimitive.RootProvider
      ref={ref}
      data-slot="splitter-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      style={{ ...rootStyle, ...style }}
      {...props}
    />
  );
});

const SplitterPanel = forwardRef<
  ComponentRef<typeof SplitterPrimitive.Panel>,
  ComponentProps<typeof SplitterPrimitive.Panel>
>(function SplitterPanel({ className, ...props }, ref) {
  return (
    <SplitterPrimitive.Panel
      ref={ref}
      data-slot="splitter-panel"
      className={clsx(styles.panel, normalizeClassName(className))}
      {...props}
    />
  );
});

const SplitterResizeTrigger = forwardRef<
  ComponentRef<typeof SplitterPrimitive.ResizeTrigger>,
  ComponentProps<typeof SplitterPrimitive.ResizeTrigger>
>(function SplitterResizeTrigger({ className, ...props }, ref) {
  return (
    <SplitterPrimitive.ResizeTrigger
      ref={ref}
      data-slot="splitter-resize-trigger"
      className={clsx(styles.resizeTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const SplitterResizeTriggerIndicator = forwardRef<
  ComponentRef<typeof SplitterPrimitive.ResizeTriggerIndicator>,
  ComponentProps<typeof SplitterPrimitive.ResizeTriggerIndicator>
>(function SplitterResizeTriggerIndicator({ className, ...props }, ref) {
  return (
    <SplitterPrimitive.ResizeTriggerIndicator
      ref={ref}
      data-slot="splitter-resize-trigger-indicator"
      className={clsx(styles.resizeTriggerIndicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const Splitter = Object.assign(SplitterRoot, {
  Root: SplitterRoot,
  RootProvider: SplitterRootProvider,
  Panel: SplitterPanel,
  ResizeTrigger: SplitterResizeTrigger,
  ResizeTriggerIndicator: SplitterResizeTriggerIndicator,
});

export { Splitter };

@layer ui.components {
  .root {
    position: relative;
    box-sizing: border-box;
    display: flex;
    min-width: var(--splitter-min-width, 0);
    min-height: var(--splitter-min-height, 0);
    overflow: hidden;
    border: var(--splitter-border-width, var(--border-width-sm)) solid
      var(--splitter-border-color, var(--color-border));
    border-radius: var(--splitter-radius, var(--radius-md));
    background-color: var(--splitter-bg, var(--color-card));
    color: var(--splitter-color, var(--color-foreground));
    box-shadow: var(--splitter-shadow, var(--shadow-sm));

    &[data-orientation='vertical'] {
      flex-direction: column;
    }

    &[data-dragging] {
      cursor: col-resize;

      &[data-orientation='vertical'] {
        cursor: row-resize;
      }
    }
  }

  .panel {
    box-sizing: border-box;
    min-width: var(--splitter-panel-min-width, 0);
    min-height: var(--splitter-panel-min-height, 12.5rem);
    padding: var(--splitter-panel-padding, var(--spacing-4));
    overflow: auto;
    border: var(--splitter-panel-border-width, 0) solid
      var(--splitter-panel-border-color, var(--color-border));
    border-radius: var(--splitter-panel-radius, 0);
    background-color: var(--splitter-panel-bg, var(--color-card));
    color: var(--splitter-panel-color, var(--color-card-foreground));
    box-shadow: var(--splitter-panel-shadow, none);

    &[data-dragging] {
      user-select: none;
    }
  }

  .root[data-orientation='vertical'] > .panel {
    min-height: var(--splitter-panel-min-height-vertical, 0);
  }

  .resizeTrigger {
    position: relative;
    z-index: 1;
    box-sizing: border-box;
    display: flex;
    flex: 0 0 var(--splitter-resize-trigger-line-size, 1px);
    align-items: center;
    justify-content: center;
    width: var(--splitter-resize-trigger-line-size, 1px);
    min-width: var(--splitter-resize-trigger-line-size, 1px);
    padding: 0;
    border: 0;
    background-color: var(--splitter-resize-trigger-bg, transparent);
    appearance: none;
    cursor: col-resize;
    outline: 0;
    touch-action: none;
    transition: opacity var(--splitter-transition, var(--transition-default));

    &::before {
      position: absolute;
      width: var(--splitter-resize-trigger-line-size, 1px);
      height: var(--splitter-resize-trigger-line-length, 100%);
      border-radius: var(--splitter-resize-trigger-line-radius, var(--radius-full));
      background-color: var(--splitter-resize-trigger-line-color, var(--color-border));
      content: '';
      transition:
        background-color var(--splitter-transition, var(--transition-default)),
        opacity var(--splitter-transition, var(--transition-default));
    }

    &::after {
      position: absolute;
      z-index: 1;
      width: var(--splitter-resize-trigger-size, 0.625rem);
      height: 100%;
      content: '';
    }

    &[data-orientation='vertical'] {
      width: 100%;
      min-width: 0;
      height: var(--splitter-resize-trigger-line-size, 1px);
      min-height: var(--splitter-resize-trigger-line-size, 1px);
      cursor: row-resize;

      &::before {
        width: var(--splitter-resize-trigger-line-length, 100%);
        height: var(--splitter-resize-trigger-line-size, 1px);
      }

      &::after {
        width: 100%;
        height: var(--splitter-resize-trigger-size, 0.625rem);
      }
    }

    &:focus-visible {
      &::before {
        background-color: var(
          --splitter-resize-trigger-line-color-focus,
          var(--splitter-resize-trigger-line-color, var(--color-border))
        );
      }
    }

    &[data-dragging] {
      &::before {
        background-color: var(
          --splitter-resize-trigger-line-color-dragging,
          color-mix(
            in oklab,
            var(--splitter-resize-trigger-line-color, var(--color-border)) 72%,
            var(--color-muted-foreground)
          )
        );
      }
    }

    &[data-disabled] {
      cursor: default;
      opacity: var(--splitter-disabled-opacity, var(--opacity-disabled));
    }
  }

  @media (hover: hover) {
    .resizeTrigger:hover:not(:disabled, [data-disabled]) {
      &::before {
        background-color: var(
          --splitter-resize-trigger-line-color-hover,
          color-mix(
            in oklab,
            var(--splitter-resize-trigger-line-color, var(--color-border)) 72%,
            var(--color-muted-foreground)
          )
        );
      }
    }
  }

  .resizeTriggerIndicator {
    position: absolute;
    inset-block-start: 50%;
    inset-inline-start: 50%;
    z-index: 2;
    box-sizing: border-box;
    width: var(--splitter-resize-trigger-indicator-width, 0.375rem);
    height: var(--splitter-resize-trigger-indicator-height, 1.5rem);
    border: var(--splitter-resize-trigger-indicator-border-width, var(--border-width-sm)) solid
      var(--splitter-resize-trigger-indicator-border-color, var(--color-border));
    border-radius: var(--splitter-resize-trigger-indicator-radius, var(--radius-full));
    background-color: var(--splitter-resize-trigger-indicator-bg, var(--color-background));
    box-shadow: var(--splitter-resize-trigger-indicator-shadow, var(--shadow-sm));
    pointer-events: none;
    transform: translate(-50%, -50%);
    transition:
      border-color var(--splitter-transition, var(--transition-default)),
      box-shadow var(--splitter-transition, var(--transition-default));

    &[data-orientation='vertical'] {
      width: var(--splitter-resize-trigger-indicator-height, 1.5rem);
      height: var(--splitter-resize-trigger-indicator-width, 0.375rem);
    }
  }

  .resizeTrigger[data-dragging] .resizeTriggerIndicator {
    border-color: var(
      --splitter-resize-trigger-indicator-border-color-dragging,
      var(--splitter-resize-trigger-indicator-border-color, var(--color-border))
    );
    background-color: var(
      --splitter-resize-trigger-indicator-bg-dragging,
      var(--splitter-resize-trigger-indicator-bg, var(--color-background))
    );
    box-shadow: var(
      --splitter-resize-trigger-indicator-shadow-dragging,
      var(--splitter-resize-trigger-indicator-shadow, var(--shadow-sm))
    );
  }

  .resizeTrigger:focus-visible:not([data-dragging]) .resizeTriggerIndicator {
    box-shadow: var(
      --splitter-resize-trigger-indicator-shadow-focus,
      var(--splitter-resize-trigger-indicator-shadow, var(--shadow-sm))
    );
  }

  .resizeTrigger[data-disabled] .resizeTriggerIndicator {
    visibility: hidden;
  }
}
